import React from "react";
import {
  SafeAreaView,
  View,
  Text,
  StyleSheet,
  ScrollView,
  Pressable,
} from "react-native";
import { useNavigation } from "@react-navigation/native";
import { useTranslation } from "../i18n";

const GREEN = "#2F7D3A";
const DARK_GREEN = "#0F3C2F";

const PLATE_WIDTH = 220;
const PLATE_HEIGHT = 40;

export default function OfficialControlScreen() {
  const navigation = useNavigation();
  const { t } = useTranslation();

  // ✅ Random/static data for now (same format you gave)
  const data = {
    plateNumber: "CE 458-Y",
    vehicle: {
      model: "Toyota Yaris (Sedan)",
      owner: "NGOUMOU Jean-Pierre",
    },
    licence: {
      number: "CUY-2026-TX-8842",
      validity: "01/01/2026 au 31/12/2026",
      zone: "Yaoundé Urbain",
      doorNumber: "1055-B",
    },
    driver: {
      name: "FOUDA MEKONGO Christian",
      permitNumber: "04/1055/B/2018",
      category: "B",
      cni: "112455987",
    },
    insurance: {
      company: "ACTIVA Assurance",
      expiry: "15/06/2026",
      status: "VALIDE",
    },
  };

  return (
    <SafeAreaView style={S.safe}>
      <ScrollView contentContainerStyle={S.scroll} showsVerticalScrollIndicator={false}>
        {/* ===== TOP BAR ===== */}
        <View style={S.topBar}>
          <Pressable onPress={() => navigation.goBack()} style={S.backBtn}>
            <Text style={S.backIcon}>‹</Text>
            <Text style={S.backText}>{t("common.back")}</Text>
          </Pressable>
        </View>

        {/* ===== HEADER / STATUS ===== */}
        <View style={S.header}>
          <View style={S.statusPill}>
            <View style={S.statusDot} />
            <Text style={S.statusText}>{t("official.statusAuthorized")}</Text>
          </View>

          {/* Plate (same style language as HomeScreen) */}
          <View style={S.plateWrap}>
            <View style={S.plateBox}>
              <Text style={S.plateText}>{data.plateNumber}</Text>
            </View>
          </View>
        </View>

        {/* ===== SECTION: VEHICLE ID ===== */}
        <View style={S.card}>
          <Text style={S.cardTitle}>{t("official.vehicle.title")}</Text>

          <Row label={t("official.vehicle.plate")} value={data.plateNumber} />
          <Row label={t("official.vehicle.model")} value={data.vehicle.model} />
          <Row label={t("official.vehicle.owner")} value={data.vehicle.owner} />
        </View>

        {/* ===== SECTION: LICENCE ===== */}
        <View style={S.card}>
          <Text style={S.cardTitle}>{t("official.licence.title")}</Text>

          <Row label={t("official.licence.number")} value={data.licence.number} />
          <Row label={t("official.licence.validity")} value={data.licence.validity} />
          <Row label={t("official.licence.zone")} value={data.licence.zone} />
          <Row label={t("official.licence.doorNumber")} value={data.licence.doorNumber} />
        </View>

        {/* ===== SECTION: DRIVER ===== */}
        <View style={S.card}>
          <Text style={S.cardTitle}>{t("official.driver.title")}</Text>

          <Row label={t("official.driver.name")} value={data.driver.name} />
          <Row label={t("official.driver.permit")} value={data.driver.permitNumber} />
          <Row label={t("official.driver.category")} value={data.driver.category} />
          <Row label={t("official.driver.cni")} value={data.driver.cni} />
        </View>

        {/* ===== SECTION: INSURANCE ===== */}
        <View style={S.card}>
          <Text style={S.cardTitle}>{t("official.insurance.title")}</Text>

          <Row label={t("official.insurance.company")} value={data.insurance.company} />
          <Row label={t("official.insurance.expiry")} value={data.insurance.expiry} />

          <View style={S.row}>
            <Text style={S.label}>{t("official.insurance.status")}</Text>
            <Text style={[S.value, { color: GREEN }]}>{data.insurance.status}</Text>
          </View>
        </View>
      </ScrollView>
    </SafeAreaView>
  );
}

function Row({ label, value }) {
  return (
    <View style={S.row}>
      <Text style={S.label}>{label}</Text>
      <Text style={S.value}>{value}</Text>
    </View>
  );
}

const S = StyleSheet.create({
  safe: { flex: 1, backgroundColor: "#F5F5F5" },
  scroll: { paddingHorizontal: 18, paddingTop: 10, paddingBottom: 24 },

  topBar: {
    width: "100%",
    flexDirection: "row",
    justifyContent: "flex-start",
    marginBottom: 6,
  },
  backBtn: {
    height: 34,
    paddingHorizontal: 12,
    borderRadius: 18,
    backgroundColor: DARK_GREEN,
    flexDirection: "row",
    alignItems: "center",
    gap: 8,
  },
  backIcon: { color: "#fff", fontSize: 18, fontWeight: "900", lineHeight: 18 },
  backText: { color: "#fff", fontSize: 13, fontWeight: "800", letterSpacing: 0.2 },

  header: {
    alignItems: "center",
    marginBottom: 14,
  },
  statusPill: {
    flexDirection: "row",
    alignItems: "center",
    gap: 10,
    backgroundColor: "rgba(47,125,58,0.12)",
    borderColor: "rgba(47,125,58,0.25)",
    borderWidth: 1,
    paddingHorizontal: 14,
    paddingVertical: 10,
    borderRadius: 999,
    marginTop: 6,
  },
  statusDot: {
    width: 10,
    height: 10,
    borderRadius: 5,
    backgroundColor: GREEN,
  },
  statusText: {
    color: GREEN,
    fontSize: 14,
    fontWeight: "900",
    letterSpacing: 0.4,
    textTransform: "uppercase",
  },

  plateWrap: { marginTop: 12, alignItems: "center" },
  plateBox: {
    width: PLATE_WIDTH,
    height: PLATE_HEIGHT,
    borderRadius: 16,
    borderWidth: 3,
    borderColor: GREEN,
    backgroundColor: "#FFFFFF",
    alignItems: "center",
    justifyContent: "center",
  },
  plateText: {
    fontSize: 24,
    fontWeight: "800",
    letterSpacing: 1,
    color: "#111827",
  },

  card: {
    backgroundColor: "#FFFFFF",
    borderRadius: 18,
    padding: 14,
    marginTop: 12,
    shadowColor: "#000",
    shadowOpacity: 0.08,
    shadowRadius: 14,
    shadowOffset: { width: 0, height: 10 },
    elevation: 4,
    borderWidth: 1,
    borderColor: "rgba(0,0,0,0.05)",
  },
  cardTitle: {
    fontSize: 12,
    fontWeight: "900",
    letterSpacing: 1,
    color: "#111827",
    textTransform: "uppercase",
    marginBottom: 10,
  },

  row: {
    flexDirection: "row",
    alignItems: "flex-start",
    justifyContent: "space-between",
    gap: 12,
    paddingVertical: 7,
    borderTopWidth: 1,
    borderTopColor: "rgba(0,0,0,0.06)",
  },
  label: {
    flex: 1,
    color: "rgba(17,24,39,0.65)",
    fontSize: 13,
    fontWeight: "700",
  },
  value: {
    flex: 1,
    textAlign: "right",
    color: "#111827",
    fontSize: 13,
    fontWeight: "800",
  },
});
